  const csvStream = fs.createReadStream(CSV_PATH);

  await client.insert({
    table: 'employees',
    values: csvStream,
    format: 'CSVWithNames',
  });

  await fs.promises.writeFile(OUTPUT_LOG, 'Success');
}

main()
  .then(() => client.close())
  .catch(async (error) => {
    console.error(error);
    try {
      await client.close();
    } catch (closeError) {
      console.error(closeError);
    }
    process.exit(1);
  });
